app = Flask(__name__)

# Database setup (using SQLite for simplicity)
import sqlite3
conn = sqlite2.connect('labels.db')
cursor = conn.cursor()

# Create table if not exists
cursor.execute('''CREATE TABLE IF NOT EXISTS labels
                 (id INTEGER PRIMARY KEY AUTOINCREMENT,
                  image BLOB,
                  label TEXT)''')

# Function to aggregate labels using majority voting
def aggregate_labels(labels):
    from collections import Counter
    counts = Counter(label for _, label in labels)
    return max(counts, key=counts.get)

# Route to accept new labels via REST API
@app.route('/label', methods=['POST'])
def label_image():
    data = request.json
    image_data = data['image']
    annotator_id = data['annotator_id']
    label = data['label']

    # Store label in database
    cursor.execute("INSERT INTO labels (image, label) VALUES (?, ?)", (image_data, label))
    conn.commit()

    return jsonify({'message': 'Label accepted'}), 200

# Route to retrieve labeled images for training
@app.route('/train', methods=['GET'])
def train_model():
    # Retrieve all labels from database
    cursor.execute("SELECT image, label FROM labels")
    labels = [(image_data, label) for image_data, label in cursor.fetchall()]

    # Aggregate labels using majority voting
    aggregated_labels = aggregate_labels(labels)

    # Split data into training and test sets (no validation set)
    X_train, X_test, y_train, y_test = train_test_split([label[0] for label in labels], [aggregated_labels for _ in range(len(labels))], test_size=0.2, random_state=42)

    # Train logistic regression model
    model = LogisticRegression()
    model.fit(X_train, y_train)

    return jsonify({'model': 'trained'}), 200

